const today = new Date();
const todayMonth = today.getMonth() + 1;
const todayDay = today.getDate();

const birthdays = [];

for (const item of $input.all()) {
  const row = item.json;

  if (!row.Name || !row.Email || !row.Birthday) continue;

  let bday;
  const raw = String(row.Birthday).trim();

  // Support formats: YYYY-MM-DD, DD/MM/YYYY, MM/DD/YYYY
  if (raw.includes('-')) {
    const parts = raw.split('-');
    bday = { month: parseInt(parts[1]), day: parseInt(parts[2]) };
  } else if (raw.includes('/')) {
    const parts = raw.split('/');
    // Detect DD/MM/YYYY vs MM/DD/YYYY by value range
    if (parseInt(parts[0]) > 12) {
      bday = { month: parseInt(parts[1]), day: parseInt(parts[0]) };
    } else {
      bday = { month: parseInt(parts[0]), day: parseInt(parts[1]) };
    }
  } else {
    continue;
  }

  if (bday.month === todayMonth && bday.day === todayDay) {
    const birthYear = raw.split(/[-\/]/)[0];
    const age = (birthYear.length === 4) ? today.getFullYear() - parseInt(birthYear) : null;

    birthdays.push({
      json: {
        name: String(row.Name).trim(),
        email: String(row.Email).trim(),
        birthday: raw,
        department: String(row.Department || '').trim(),
        customMessage: String(row.Message || '').trim(),
        age: age,
        ageText: age ? `You're turning ${age} today! ` : ''
      }
    });
  }
}

if (birthdays.length === 0) {
  return [{ json: { noBirthdays: true, message: 'No birthdays today' } }];
}

return birthdays;

const person = $input.item.json;

const customMsg = person.customMessage;
const name = person.name;
const dept = person.department ? ` from ${person.department}` : '';
