  .footer { text-align: center; padding: 20px; background: #f9f9f9; color: #aaa; font-size: 12px; }
</style>
</head>
<body>
  <div class="card">
    <div class="header">
      <h1>🎉 Happy Birthday!</h1>
      <p>Wishing you a wonderful day, ${name}${dept}!</p>
